@app.cell(hide_code=True)
def engine(CATS, COMPONENTS, ORDER, STRUCTURAL_GAPS):
    import math
    import re
    from collections import Counter

    STOP = set("a an and are as at be but by for from has have in is it its of "
               "on or that the this to was were will with we our your you they "
               "their not can".split())

    def tok(text):
        return [t for t in re.findall(r"[a-z0-9]+", text.lower())
                if len(t) > 1 and t not in STOP]

    # Query-side synonym expansion (weight 0.5). Small and documented: bridges
    # builder vocabulary ("privacy", "offline") to map-description vocabulary
    # ("local", "self-hosted", "edge").
    SYNONYMS = {
        "privacy": ["private", "local", "self", "hosted"],
        "private": ["local", "self", "hosted"],
        "own": ["self", "hosted"],
        "premises": ["self", "hosted", "local"],
        "offline": ["local", "device", "edge"],
        "assistant": ["chat"],
        "chatbot": ["chat", "assistant"],
        "voice": ["speech", "audio"],
        "speech": ["audio", "voice"],
        "build": ["framework", "library"],
        "document": ["documents", "pdf", "text"],
        "documents": ["document", "pdf", "text"],
        "search": ["retrieval", "index"],
        "citations": ["sources", "research"],
        "knowledge": ["retrieval", "rag", "documents"],
        "tune": ["tuning", "finetuning", "training"],
        "finetune": ["finetuning", "tuning", "training", "lora"],
        "monitor": ["observability", "tracing", "monitoring"],
        "cheap": ["cost", "efficient"],
        "fast": ["latency", "throughput"],
    }

    # Taxonomy boost keywords per category (the M1 taxonomy made searchable).
    CAT_KW = {
        "base_pretrained": set(tok("base pretrained foundation pretraining train scratch weights multilingual language")),
        "finetuned_chat": set(tok("chat assistant instruct conversation reasoning coder coding model llm")),
        "inference_code": set(tok("inference serving serve engine runtime quantized local gpu cpu latency throughput")),
        "finetuning_code": set(tok("finetuning fine tuning train training lora rlhf rl adapt instruction")),
        "evaluation_code": set(tok("evaluation eval harness benchmark test grade quality regression")),
        "benchmark_eval_data": set(tok("benchmark dataset eval questions test math code knowledge")),
        "orchestration_agents": set(tok("agent agents orchestration framework workflow autonomous plan rag retrieval chain")),
        "ui_api": set(tok("ui interface chat frontend gateway api proxy router self hosted web app")),
        "telemetry_observability": set(tok("observability tracing telemetry monitoring logging cost analytics debug")),
        "agent_tools_protocols": set(tok("tools protocol vector database search retrieval scrape browse mcp embedding index")),
        "deployment": set(tok("deploy deployment sandbox container serverless runtime host hosting cluster cloud")),
    }
    OPEN_CLASSES = {"open_source", "open", "open_weights", "open_core"}
    # Calibrated on the preset queries (see methodology).
    TH = {"strong": 0.10, "show": 0.04, "gap": 0.05}

    _docs = [tok(" ".join([p["n"], p.get("o") or "", p.get("t") or "",
                           CATS[p["c"]]["label"], p.get("d") or ""]))
             for p in COMPONENTS]
    _N = len(_docs)
    _df = Counter()
    for _d in _docs:
        _df.update(set(_d))
    _idf = {t: math.log(_N / (1 + n)) + 1 for t, n in _df.items()}
    _default_idf = math.log(_N) + 1

    def _vec(weights):
        v = {t: w * _idf.get(t, _default_idf) for t, w in weights.items()}
        norm = math.sqrt(sum(x * x for x in v.values())) or 1.0
        return {t: x / norm for t, x in v.items()}

    _dvecs = [_vec({t: 1 + math.log(c) for t, c in Counter(d).items()})
              for d in _docs]

    def search(query, open_only=True):
        qt = tok(query)
        qweights = dict.fromkeys(qt, 1.0)
        for t in qt:
            for s in SYNONYMS.get(t, []):
                qweights.setdefault(s, 0.5)
        qv = _vec(qweights)
        qset = set(qweights)
        out = []
        for p, dv in zip(COMPONENTS, _dvecs):
            if open_only and p.get("oc") not in OPEN_CLASSES:
                continue
            cos = sum(w * dv.get(t, 0.0) for t, w in qv.items())
            boost = 1.0 + (0.25 if qset & CAT_KW[p["c"]] else 0.0)
            adopt = 1.0 + 0.05 * (((p.get("a") or 3) - 3) / 2)
            out.append((cos * boost * adopt, p))
        out.sort(key=lambda x: (-x[0], x[1]["n"]))
        return out

    def gap_triggers(query):
        qset = set(tok(query))
        return [(label, why) for kws, label, why in STRUCTURAL_GAPS
                if qset & set(kws)]

    BY_NAME = {p["n"]: p for p in COMPONENTS}
    return BY_NAME, CAT_KW, OPEN_CLASSES, TH, gap_triggers, search, tok


