@app.cell(hide_code=True)
def kpis(GALLERY, N_TOTAL, ORDER, mo):
    _distinct = {name for g in GALLERY for _cid, comps in g["layers"] for name, _b in comps}
    _known = sum(1 for g in GALLERY for _cid, comps in g["layers"] for _n, b in comps if b == "known_build")
    _gaps = sum(len(g["gaps"]) for g in GALLERY)
    mo.hstack(
        [
            mo.stat(value=f"{len(GALLERY)}", label="Reference products", bordered=True,
                    caption="curated build patterns"),
            mo.stat(value=f"{len(_distinct)}", label="Components cited", bordered=True,
                    caption=f"of {N_TOTAL} scored in the map"),
            mo.stat(value=f"{_known}", label="Known-build edges", bordered=True,
                    caption="from documented real-world builds"),
            mo.stat(value=f"{len(ORDER)}", label="Stack layers", bordered=True,
                    caption="across 3 arcs of the map"),
            mo.stat(value=f"{_gaps}", label="Gap signals", bordered=True,
                    caption="weak or missing layers surfaced"),
        ],
        widths="equal", gap=1,
    )
    return


