@app.cell(hide_code=True)
def lookup_ui(PRESETS, mo):
    lookup_preset = mo.ui.dropdown(options=PRESETS, value=PRESETS[0], label="Preset description")
    lookup_query = mo.ui.text_area(placeholder="…or describe your own product here (overrides the preset)", rows=2, full_width=True)
    lookup_open_only = mo.ui.switch(value=True, label="Open components only")
    mo.vstack([mo.hstack([lookup_preset, lookup_open_only], justify="start", gap=2), lookup_query], gap=0.5)
    return lookup_open_only, lookup_preset, lookup_query


@app.cell(hide_code=True)
def lookup_results(C, CATS, CAT_KW, F, OPEN_LABEL, ORDER, TH, gap_triggers,
                   lookup_open_only, lookup_preset, lookup_query, mo, search, tok):
    _q = (lookup_query.value or "").strip() or lookup_preset.value
    _open_only = lookup_open_only.value
    _res = search(_q, open_only=_open_only)
    _res_open = _res if _open_only else search(_q, open_only=True)
    _res_all = search(_q, open_only=False) if _open_only else _res

    _best = {}
    for _s, _p in _res:
        _best.setdefault(_p["c"], _s)
    _best_open = {}
    for _s, _p in _res_open:
        _best_open.setdefault(_p["c"], _s)
    _best_all = {}
    for _s, _p in _res_all:
        _best_all.setdefault(_p["c"], _s)
    _max = max((_s for _s, _p in _res), default=0.0) or 1.0

    _ARCS = ["Models", "Model code & data", "System / Product-UX"]
    _groups = ""
    for _arc in _ARCS:
        _cats = [c for c in ORDER if CATS[c]["arc"] == _arc and _best.get(c, 0.0) >= TH["show"]]
        if not _cats:
            continue
        _cat_html = ""
        for _cid in _cats:
            _top = [(s, p) for s, p in _res if p["c"] == _cid][:3]
            _rows = ""
            for _s, _p in _top:
                _ol, _ock = OPEN_LABEL.get(_p.get("oc"), ("n/a", "ink_3"))
                _strong = _s >= TH["strong"]
                _w = max(3, round(_s / _max * 100))
                _rows += (
                    f'<div style="display:flex; align-items:center; gap:10px; margin:4px 0;">'
                    f'<div class="pv-details" data-pid="{_p["n"]}" title="Click for the full scorecard" '
                    f'style="min-width:200px; font-family:{F["body"]}; font-size:0.84rem; cursor:pointer; '
                    f'color:{C["ink"]}; font-weight:{600 if _strong else 400};">{_p["n"]}'
                    f'<span style="font-family:{F["mono"]}; font-size:0.6rem; color:{C[_ock]}; '
                    f'margin-left:7px; text-transform:uppercase;">{_ol}</span></div>'
                    f'<div style="flex:1; background:{C["paper_2"]}; border-radius:2px; height:8px;">'
                    f'<div style="width:{_w}%; height:8px; border-radius:2px; '
                    f'background:{C["accent"] if _strong else C["rule"]};"></div></div>'
                    f'<div style="font-family:{F["mono"]}; font-size:0.7rem; color:{C["ink_3"]}; '
                    f'min-width:42px; text-align:right;">{_s:.3f}</div></div>'
                )
            _cat_html += (
                f'<div style="margin:10px 0 14px;">'
                f'<div style="font-family:{F["mono"]}; font-size:0.7rem; color:{C["ink_3"]}; '
                f'text-transform:uppercase; letter-spacing:0.04em; margin-bottom:4px;">{CATS[_cid]["label"]}'
                f' · <span style="color:{C["ink_2"]};">{CATS[_cid]["desc"]}</span></div>{_rows}</div>'
            )
        _groups += (
            f'<div style="margin:14px 0;">'
            f'<div style="font-family:{F["mono"]}; font-size:0.64rem; color:{C["accent"]}; '
            f'letter-spacing:0.08em; text-transform:uppercase; border-bottom:1px solid {C["paper_2"]}; '
            f'padding-bottom:3px; margin-bottom:6px;">{_arc}</div>{_cat_html}</div>'
        )
    if not _groups:
        _groups = (
            f'<p style="font-family:{F["body"]}; font-size:0.9rem; color:{C["signal"]}; line-height:1.5;">'
            f'No layer clears the display threshold for this description — itself a strong gap signal: '
            f'the open stack has little to offer this product today.</p>'
        )

    # Gap signals: layers the query implies (taxonomy keywords) where the best
    # OPEN match stays under threshold; layers only closed components answer;
    # and structural absences triggered by query keywords.
    _qtok = set(tok(_q))
    _weak = [c for c in ORDER if (_qtok & CAT_KW[c]) and _best_open.get(c, 0.0) < TH["gap"]]
    _closed_only = [c for c in ORDER
                    if _best_all.get(c, 0.0) >= TH["strong"] and _best_open.get(c, 0.0) < TH["gap"]]
    _structural = gap_triggers(_q)
    _gap_items = ""
    for _c in _weak:
        _gap_items += (
            f'<div style="margin:5px 0; font-size:0.84rem; color:{C["ink_2"]}; line-height:1.5;">'
            f'<span style="font-family:{F["mono"]}; font-size:0.6rem; color:white; background:{C["warm"]}; '
            f'padding:2px 7px; border-radius:9px; text-transform:uppercase; margin-right:8px;">weak layer</span>'
            f'<strong>{CATS[_c]["label"]}</strong> — your description implies this layer, but the best '
            f'open match scores {_best_open.get(_c, 0.0):.3f} (threshold {TH["gap"]}).</div>'
        )
    for _c in _closed_only:
        _gap_items += (
            f'<div style="margin:5px 0; font-size:0.84rem; color:{C["ink_2"]}; line-height:1.5;">'
            f'<span style="font-family:{F["mono"]}; font-size:0.6rem; color:white; background:{C["warm"]}; '
            f'padding:2px 7px; border-radius:9px; text-transform:uppercase; margin-right:8px;">closed only</span>'
            f'<strong>{CATS[_c]["label"]}</strong> — this layer answers your description, but only with '
            f'closed components.</div>'
        )
    for _t, _w in _structural:
        _gap_items += (
            f'<div style="margin:5px 0; font-size:0.84rem; color:{C["ink_2"]}; line-height:1.5;">'
            f'<span style="font-family:{F["mono"]}; font-size:0.6rem; color:white; background:{C["signal"]}; '
            f'padding:2px 7px; border-radius:9px; text-transform:uppercase; margin-right:8px;">structural</span>'
            f'<strong>{_t}</strong> — {_w}</div>'
        )
    _gap_panel = ""
    if _gap_items:
        _gap_panel = (
            f'<div style="margin:18px 0 0; padding:12px 16px; background:{C["paper"]}; '
            f'border-left:3px solid {C["signal"]}; border-radius:0 4px 4px 0;">'
            f'<div style="font-family:{F["mono"]}; font-size:0.62rem; color:{C["signal"]}; '
            f'letter-spacing:0.08em; text-transform:uppercase; margin-bottom:4px;">'
            f'Gap signals for this description</div>{_gap_items}'
            f'<div style="font-family:{F["body"]}; font-size:0.76rem; color:{C["ink_3"]}; margin-top:8px;">'
            f'These signals feed the map’s gap analysis: a sensible product description that the stack '
            f'answers weakly marks a place where open-source AI needs investment.</div></div>'
        )
    mo.Html(
        f'<div style="margin:8px 0 10px; padding:16px 20px; background:white; '
        f'border:1px solid {C["rule"]}; border-radius:6px;">'
        f'<div style="font-family:{F["mono"]}; font-size:0.66rem; color:{C["ink_3"]}; margin-bottom:8px;">'
        f'Query · “{_q}” · {"open components only" if _open_only else "all components"} '
        f'· top 3 per layer, layers shown when best score ≥ {TH["show"]}</div>'
        f'{_groups}{_gap_panel}</div>'
    )
    return


@app.cell(hide_code=True)
def gaps_aggregate(C, CATS, F, GALLERY, ORDER, mo):
    # Demand vs gaps across the whole gallery: which layers products actually
    # pull on, and which capabilities broke composition. Feeds Gap Analysis.
    _demand = {c: 0 for c in ORDER}
    for _g in GALLERY:
        for _cid, _comps in _g["layers"]:
            _demand[_cid] += 1
    _maxd = max(_demand.values()) or 1
    _bars = ""
    for _cid in sorted(ORDER, key=lambda c: -_demand[c]):
        _w = round(_demand[_cid] / _maxd * 100)
        _bars += (
            f'<div style="display:flex; align-items:center; gap:10px; margin:5px 0;">'
            f'<div style="min-width:210px; font-family:{F["mono"]}; font-size:0.72rem; '
            f'color:{C["ink_2"]};">{CATS[_cid]["label"]}</div>'
            f'<div style="flex:1; background:{C["paper_2"]}; border-radius:2px; height:12px;">'
            f'<div style="width:{_w}%; height:12px; border-radius:2px; background:{C["accent"]};"></div></div>'
            f'<div style="font-family:{F["mono"]}; font-size:0.74rem; color:{C["ink_3"]}; '
            f'min-width:80px; text-align:right;">{_demand[_cid]} of {len(GALLERY)}</div></div>'
        )
    _agg = {}
    for _g in GALLERY:
        for _k, _t, _w in _g["gaps"]:
            _agg.setdefault(_t, {"kind": _k, "why": _w, "products": []})
            _agg[_t]["products"].append(_g["title"])
    _gap_rows = "".join(
        f'<tr style="border-bottom:1px solid {C["paper_2"]};">'
        f'<td style="padding:8px 10px;"><span style="font-family:{F["mono"]}; font-size:0.62rem; color:white; '
        f'background:{C["signal"] if _v["kind"] == "structural" else C["warm"]}; padding:2px 8px; '
        f'border-radius:9px; text-transform:uppercase;">{_v["kind"].replace("_", " ")}</span></td>'
        f'<td style="padding:8px 10px; font-family:{F["body"]}; font-size:0.86rem; color:{C["ink"]}; '
        f'font-weight:600; white-space:nowrap;">{_t}</td>'
        f'<td style="padding:8px 10px; font-family:{F["body"]}; font-size:0.82rem; color:{C["ink_2"]}; '
        f'line-height:1.45;">{_v["why"]}</td>'
        f'<td style="padding:8px 10px; font-family:{F["body"]}; font-size:0.78rem; color:{C["ink_3"]};">'
        f'{", ".join(_v["products"])}</td></tr>'
        for _t, _v in sorted(_agg.items(), key=lambda kv: (kv[1]["kind"] != "structural", -len(kv[1]["products"])))
    )
    _head = "".join(
        f'<th style="padding:7px 10px; font-family:{F["mono"]}; font-size:9px; color:{C["ink_3"]}; '
        f'text-transform:uppercase; letter-spacing:0.05em; text-align:left;">{_h}</th>'
        for _h in ["Kind", "Missing capability", "Why it matters", "Blocked / weakened products"]
    )
    mo.Html(
        f'<div style="margin:44px 0 20px; padding:24px 0 0; border-top:2px solid {C["accent"]};">'
        f'<div style="font-family:{F["mono"]}; font-size:10px; color:{C["accent"]}; '
        f'letter-spacing:0.1em; text-transform:uppercase; margin-bottom:8px;">Gaps the products reveal</div>'
        f'<h2 style="font-family:{F["headline"]}; font-size:1.6rem; font-weight:500; color:{C["ink"]}; '
        f'margin:0 0 12px; letter-spacing:-0.015em;">Where composition breaks down</h2>'
        f'<p style="font-family:{F["body"]}; font-size:0.95rem; color:{C["ink_2"]}; margin:0 0 16px; line-height:1.6;">'
        f'Layer demand first: how many of the {len(GALLERY)} reference products draw on each layer. '
        f'The map’s well-stocked layers — inference, evaluation, orchestration — are exactly the '
        f'ones everything needs, which is reassuring. The gap table below is the more important half: '
        f'capabilities that sensible products need and the map answers weakly or not at all. '
        f'<strong>This table is an input, not a footnote</strong> — each row is a candidate category or '
        f'scoring target for the next iteration of gap analysis.</p>'
        f'<div style="margin:0 0 22px;">{_bars}</div>'
        f'<table style="border-collapse:collapse; width:100%;">'
        f'<thead><tr style="border-bottom:2px solid {C["rule"]};">{_head}</tr></thead>'
        f'<tbody>{_gap_rows}</tbody></table></div>'
    )
    return


@app.cell(hide_code=True)
def methodology(C, F, TH, mo):
    _ps = [
        f"""<strong>What counts as part of a product (the composition rules).</strong> A component is included in a reference product iff at least one rule fires: <strong>R1 · known build</strong> — it appears in a documented real-world build of this product pattern (eg, Open WebUI’s quickstart pairs it with Ollama; verl documents vLLM as its rollout engine; the Open LLM Leaderboard runs lm-evaluation-harness on Spaces). Curator-asserted from the component’s own documentation. <strong>R2 · documented component</strong> — the component’s documentation, as reflected in its map description, names the product pattern or role as a primary use case. <strong>R3 · similarity</strong> — TF-IDF cosine similarity between the product description and the component’s map description clears {TH["strong"]}. Gallery exemplars are selected by R1/R2 and capped at four per layer; R3 alone never makes an exemplar, only a lookup suggestion.""",
        f"""<strong>Exemplars are open-leaning by design.</strong> The map exists to chart the open stack, so gallery exemplars are drawn from open / open-core / open-weights components; closed incumbents stay visible in the parent stack map and in lookup mode with the “open components only” switch off. Where only closed components can fill a layer, that is reported as a gap, not papered over.""",
        f"""<strong>Lookup scoring.</strong> score = cosine_tfidf × (1 + 0.25·taxonomy_keyword_hit) × (1 + 0.05·(adoption−3)/2). Pure-Python TF-IDF (log-tf, smoothed idf, L2-normalized) over each component’s name, org, type, category label, and description; a small documented synonym list expands query vocabulary (“privacy” → “self-hosted, local”) at half weight. Thresholds, calibrated on the preset queries: strong match ≥ {TH["strong"]}, layer displayed ≥ {TH["show"]}, gap flagged when an implied layer’s best open match < {TH["gap"]}. Embeddings would rank better; TF-IDF ranks <em>reproducibly</em>, with no model dependency, and that trade is right for v1.""",
        f"""<strong>Gap signals are the point, not the failure mode.</strong> Three kinds: <em>weak layer</em> (your description implies a layer, the best open match stays under threshold), <em>closed only</em> (the layer answers, but only with closed components), and <em>structural</em> (no category covers the capability at all — speech, embeddings, guardrails, document parsing, training corpora, generative media). Structural absences are keyword-triggered and cross-checked against the parent map’s framework white-space. All three feed Gap Analysis and Scoring as candidate categories and scoring targets.""",
        f"""<strong>Provenance.</strong> Component records, scores, and taxonomy come from <a href="https://github.com/currentai-org/os-ai-map" target="_blank" rel="noopener" style="color:{C["accent"]}; text-decoration:underline;">currentai-org/os-ai-map</a> (the data behind the AI Stack Map); no new data was collected for this view. The gallery is curated and versioned — disagree with a composition? Open a PR. Known limits: known-build edges are curator-asserted rather than mined from deployment telemetry; descriptions are English, so lookup is English-centric; and 13 reference products sample the product space, they don’t span it.""",
    ]
    _body = "".join(
        f'<p style="font-family:{F["body"]}; font-size:0.9rem; color:{C["ink_2"]}; line-height:1.6; margin:0 0 12px;">{_p}</p>'
        for _p in _ps
    )
    mo.Html(
        f'<div style="margin:48px 0 24px; padding:24px 0 0; border-top:2px solid {C["accent"]};">'
        f'<div style="font-family:{F["mono"]}; font-size:10px; color:{C["accent"]}; letter-spacing:0.1em; '
        f'text-transform:uppercase; margin-bottom:10px;">Methodology · composition logic</div>'
        f'{_body}</div>'
    )
    return


@app.cell(hide_code=True)
def details_modal(CATS, COMPONENTS, mo):
    import json as _json
    # Same scorecard modal as the parent AI Stack Map notebook: per-component
    # payload keyed by name, delegated click handler + modal injected via a
    # hidden-iframe onload bootstrap (marimo strips <script>, so we inject
    # through the iframe into the parent document). Triggers are any element
    # with class pv-details and a data-pid attribute (gallery chips, lookup rows).
    _payload = {}
    for _p in COMPONENTS:
        _payload[_p["n"]] = {
            "product": _p["n"],
            "org": _p.get("o"),
            "type": _p.get("t"),
            "description": _p.get("d"),
            "version_note": _p.get("vn"),
            "openness": _p.get("op"),
            "adoption": _p.get("ad"),
            "capability": _p.get("cap"),
            "category_label": CATS[_p["c"]]["label"],
        }
    _pj = _json.dumps(_payload, ensure_ascii=False)
    _css = (
        ".pv-details:hover{border-color:#2a3d8f !important;box-shadow:0 1px 4px rgba(42,61,143,0.22);}"
        ".v3-bd{position:fixed;inset:0;background:rgba(26,24,20,0.55);z-index:99999;display:flex;"
        "align-items:flex-start;justify-content:center;padding:40px 20px;overflow-y:auto;font-family:Inter,system-ui,sans-serif;}"
        ".v3-modal{background:#fff;border-radius:10px;max-width:780px;width:100%;padding:24px 28px;box-shadow:0 20px 60px rgba(0,0,0,0.25);}"
        ".v3-modal h2{font-family:Fraunces,Georgia,serif;font-weight:500;font-size:1.4rem;margin:0 0 4px;color:#1a1814;}"
        ".v3-x{float:right;cursor:pointer;background:none;border:1px solid #c9bfac;border-radius:5px;padding:4px 10px;font-size:12px;color:#6b6253;}"
        ".v3-sect{margin:16px 0 6px;font-family:'JetBrains Mono',ui-monospace,monospace;font-size:10.5px;text-transform:uppercase;"
        "letter-spacing:0.08em;color:#2a3d8f;font-weight:600;border-bottom:1px solid #c9bfac;padding-bottom:4px;}"
        ".v3-row{display:flex;gap:14px;margin:5px 0;font-size:13px;color:#3a342b;}"
        ".v3-lbl{min-width:96px;color:#6b6253;font-family:'JetBrains Mono',ui-monospace,monospace;font-size:11.5px;}"
        ".v3-val{flex:1;line-height:1.45;}"
        ".v3-pill{display:inline-block;padding:2px 8px;border-radius:10px;color:#fff;font-size:11px;font-weight:600;}"
        ".v3-modal ul{margin:4px 0;padding-left:20px;font-size:12.5px;color:#3a342b;line-height:1.5;}"
        ".v3-modal a{color:#2a3d8f;text-decoration:none;}.v3-modal a:hover{text-decoration:underline;}"
    )
    _js = r'''
    (function(){
      if (window.__PV_INSTALLED__) { window.__PV_PAYLOAD__ = __PAYLOAD__; return; }
      window.__PV_INSTALLED__ = true; window.__PV_PAYLOAD__ = __PAYLOAD__;
      var esc=function(s){return String(s==null?'':s).replace(/[&<>"']/g,function(c){return ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'})[c];});};
      function ocol(sc){return sc==null?'#6b6253':(sc>=4?'#1b6b5e':(sc==3?'#d97c2a':(sc==2?'#c8341d':'#6b6253')));}
      function srcs(a){if(!a||!a.length)return '<span style="color:#aaa">no sources</span>';
        return '<ul>'+a.map(function(s){var u=s&&s.url?s.url:'';var sh=s&&s.shows?s.shows:u;
        return u?'<li><a href="'+esc(u)+'" target="_blank" rel="noopener">'+esc(sh||u)+'</a></li>':'<li>'+esc(sh)+'</li>';}).join('')+'</ul>';}
      function row(l,v){if(v==null||v==='')v='<em style="color:#aaa">n/a</em>';
        return '<div class="v3-row"><span class="v3-lbl">'+esc(l)+'</span><span class="v3-val">'+(typeof v==='string'&&v.indexOf('<')===0?v:esc(v))+'</span></div>';}
      function build(p){
        var o=p.openness||{},ad=p.adoption||{},cap=p.capability||{};
        var h='<div class="v3-bd"><div class="v3-modal"><button class="v3-x">Close ✕</button>'+
          '<h2>'+esc(p.product||'')+'</h2>'+
          '<div style="font-family:\'JetBrains Mono\',monospace;font-size:11px;color:#6b6253;margin-bottom:6px;">'+
            esc(p.org||'')+' · '+esc(p.type||'')+' · '+esc(p.category_label||'')+
            (o.class?' · <span class="v3-pill" style="background:'+ocol(o.score)+'">'+esc(o.class)+'</span>':'')+'</div>'+
          (p.description?'<div style="font-size:13px;color:#3a342b;line-height:1.5;margin:8px 0;">'+esc(p.description)+'</div>':'')+
          (p.version_note?'<div style="font-size:11.5px;color:#6b6253;line-height:1.45;margin:6px 0;">'+esc(p.version_note)+'</div>':'')+
          '<div class="v3-sect">Openness · '+(o.score==null?'n/a':o.score+'/5')+' ('+esc(o.class||'')+')</div>'+
          row('Components',o.components)+row('Why',o.note)+row('Confidence',o.confidence)+
          '<div class="v3-row"><span class="v3-lbl">Sources</span><span class="v3-val">'+srcs(o.sources)+'</span></div>'+
          '<div class="v3-sect">Adoption · '+(ad.level==null?'n/a':ad.level+'/5')+'</div>'+
          row('Reach',ad.reach)+row('Signal',ad.signal_type)+row('Detail',ad.note)+row('Confidence',ad.confidence)+
          '<div class="v3-row"><span class="v3-lbl">Sources</span><span class="v3-val">'+srcs(ad.sources)+'</span></div>'+
          '<div class="v3-sect">Capability · '+(cap.score==null?'n/a':cap.score+'/5')+'</div>'+
          row('Basis',cap.basis)+row('Value',cap.value)+row('Detail',cap.note)+row('Confidence',cap.confidence)+
          '<div class="v3-row"><span class="v3-lbl">Sources</span><span class="v3-val">'+srcs(cap.sources)+'</span></div>'+
          '</div></div>';
        return h;
      }
      function open(p){var ex=document.getElementById('__pv_modal');if(ex)ex.remove();
        var r=document.createElement('div');r.id='__pv_modal';r.innerHTML=build(p);document.body.appendChild(r);
        var bd=r.querySelector('.v3-bd');function cl(){r.remove();document.removeEventListener('keydown',ek);}
        function ek(e){if(e.key==='Escape')cl();}
        r.querySelectorAll('.v3-x').forEach(function(b){b.addEventListener('click',cl);});
        if(bd)bd.addEventListener('click',function(e){if(e.target===bd)cl();});
        document.addEventListener('keydown',ek);}
      document.addEventListener('click',function(e){var b=e.target.closest&&e.target.closest('.pv-details');if(!b)return;
        var p=window.__PV_PAYLOAD__[b.getAttribute('data-pid')];if(p)open(p);});
    })();
    '''
    _full = ("(function(){if(!window.__PV_CSS__){window.__PV_CSS__=true;var s=document.createElement('style');"
             "s.textContent='" + _css.replace("\\", "\\\\").replace("'", "\\'") + "';document.head.appendChild(s);}})();"
             + _js.replace("__PAYLOAD__", _pj))
    _boot = _full.replace("&", "&amp;").replace('"', "&quot;").replace("<", "&lt;")
    mo.Html(
        f'<iframe srcdoc="&lt;!doctype html&gt;&lt;html&gt;&lt;/html&gt;" '
        f'style="display:none;width:0;height:0;border:0;position:absolute" onload="{_boot}"></iframe>'
    )
    return


